import axios from 'axios';

// Replace this with your actual Figma file ID
const FILE_ID = 'NBHU5lsSfPTBMnlFVPxHNB'; // Figma file ID from the URL
const FIGMA_TOKEN = 'figd_9IgwTEDRk2P6kWhTjRvtOmkFcAKniW9pPya9ohwA'; // Your Figma personal access token

// The base URL for Figma API
const FIGMA_API_URL = 'https://api.figma.com/v1';

/**
 * Recursively find all components in a node tree
 * @param {Object} node - Current node in the Figma document tree
 * @returns {Array} - List of component nodes
 */
const findComponents = (node) => {
  let components = [];
  if (node.type === 'COMPONENT' || node.type === 'INSTANCE') {
      components.push(node);
  }
  if (node.children) {
      node.children.forEach((child) => {
          components = components.concat(findComponents(child));
      });
  }
  return components;
};

/**
* Fetch all components from the Figma file
* @returns {Promise<Array>} - List of components from Figma
*/
export const fetchFigmaComponents = async () => {
  try {
      const response = await axios.get(`${FIGMA_API_URL}/files/${FILE_ID}`, {
          headers: {
              'X-Figma-Token': FIGMA_TOKEN,
          },
      });

      const root = response.data.document;
      const components = findComponents(root);
      console.log('Fetched Components:', components);
      return components;
  } catch (error) {
      console.error('Error fetching components from Figma:', error);
      throw error;
  }
};
